const cfg = $('⚙️ Load Config').item.json;
const raw = cfg.A_B_TESTING_ENABLED;
const enabled = raw === true || String(raw).toLowerCase() === 'true';
return [{ json: { A_B_TESTING_ENABLED: enabled, ...cfg } }];

const config = $('⚙️ Load Config').item.json;
const tz = config.CONTENT_DAY_TIMEZONE || config.TIMEZONE || 'UTC';
const today = new Date().toLocaleDateString('en-CA', { timeZone: tz });
const yesterday = new Date(new Date(today).getTime() - 86400000).toISOString().slice(0, 10);
const rows = $input.all().map(i => i.json);
const dateKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase() === 'date') || 'date';
const statusKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase() === 'status') || 'status';
const urlKey = Object.keys(rows[0] || {}).find(k => k.toLowerCase().includes('url') || k === 'WP URL') || 'wp_url';
const valid = rows.filter(r => {
  const d = (r[dateKey] || r.date || '').toString().slice(0, 10);
  const s = (r[statusKey] || r.status || '').toLowerCase();
  return d === yesterday && s !== 'publish_failed';
});
if (valid.length === 0) return [{ json: { noPostYesterday: true } }];
const latest = valid[valid.length - 1];
const wpUrl = (latest[urlKey] || latest.wp_url || '').toString();
const slug = wpUrl.split('/').filter(Boolean).pop() || '';
return [{ json: { ...latest, slug, wpUrl, noPostYesterday: false } }];

const raw = $input.first().json;
const post = Array.isArray(raw) ? raw[0] : raw;
if (!post || !post.link) return [{ json: { parse_error: 'No post from WP' } }];
return [{ json: post }];

const post = $input.first().json;
const title = post.title?.rendered || post.title || '';
const content = (post.content?.rendered || post.content || '').replace(/<[^>]+>/g, ' ').slice(0, 800);
const schema = JSON.stringify({
  success: true,
  data: {
    original_title: '',
    original_intro: '',
    original_cta: '',
    variant_title: '',
    variant_intro: '',
    variant_cta: ''
  },
  error: null
});
const prompt = `Return only valid JSON.\nNo text.\nNo markdown.\nNo explanations.\n\nSchema (use exactly these keys in data):\n${schema}\n\nGenerate one variant set. Extract original headline (title), first paragraph as intro, and one CTA phrase from the post below. Then write one alternate for each: variant_title (new headline), variant_intro (new first paragraph), variant_cta (new CTA). Return { \"success\": true, \"data\": { original_title, original_intro, original_cta, variant_title, variant_intro, variant_cta }, \"error\": null }.\n\nPost title: ${title}\n\nContent excerpt: ${content}`;
return [{ json: { prompt } }];

const raw = $input.first().json.response || '';
const postData = $('📌 First post from response').item.json;
const postUrl = postData.link || '';
let parsed;
try {
  const str = (typeof raw === 'string' ? raw : '').replace(/\\n/g, '\n');
  const match = str.match(/```json\\n([\\s\\S]*?)\\n```/) || str.match(/(\\{[\\s\\S]*\\})/);
  const jsonStr = match ? (match[1] || match[0] || '{}').trim() : str;
  parsed = JSON.parse(jsonStr);
} catch(e) {
  parsed = { success: false, data: null, error: { code: 'parse_error', message: e.message } };
}
const d = parsed.success && parsed.data ? parsed.data : {};
const testId = 'TEST_' + Date.now();
const createdAt = new Date().toISOString();
return [{ json: {
  test_id: testId,
  post_url: postUrl,
  original_title: d.original_title || '',
  original_intro: d.original_intro || '',
  original_cta: d.original_cta || '',
  variant_title: d.variant_title || '',
  variant_intro: d.variant_intro || '',
  variant_cta: d.variant_cta || '',
  created_at: createdAt,
  status: 'ready',
  winner: ''
} }];
